/* ============================================================
   Creator Netflix — menu & formulaire
   ============================================================ */
function buildCreatorMenu(actionPrefix){
  const f = state.netflixCreatorForm;
  const t = state.netflixCreatorType;
  return `
  <div class="creator-overlay">
    <div class="creator-menu">
      <div class="creator-title">
        <span>🎬 Créateur Netflix</span>
        <div class="creator-close" data-gaze data-action="${actionPrefix}:close">✕</div>
      </div>
      ${!t ? `
      <div class="creator-picker">
        <div class="creator-pick-btn" data-gaze data-action="${actionPrefix}:type:series">🎞️ Créer une série</div>
        <div class="creator-pick-btn" data-gaze data-action="${actionPrefix}:type:movie">🎥 Créer un film</div>
      </div>
      <div style="flex:1;display:flex;align-items:center;justify-content:center;font-size:11px;opacity:.4">
        Choisissez un type de contenu
      </div>` : `
      <div class="creator-form">
        <div class="creator-field">
          <span class="creator-label">Nom${t==='series'?' de la série':' du film'}</span>
          <div class="creator-input" style="cursor:pointer;${!f.name?'opacity:.5':''}"
            data-gaze data-action="${actionPrefix}:edit:name">
            ${f.name || '👆 1× clavier VR · 2× clavier iPhone'}
          </div>
        </div>
        <div class="creator-field">
          <span class="creator-label">Histoire / Synopsis</span>
          <div class="creator-textarea" style="cursor:pointer;${!f.story?'opacity:.5':''}"
            data-gaze data-action="${actionPrefix}:edit:story">
            ${f.story || '👆 1× clavier VR · 2× clavier iPhone'}
          </div>
        </div>
        ${t==='series' ? `
        <div class="creator-field">
          <span class="creator-label">Nombre de saisons</span>
          <div class="creator-slider-row">
            <input class="creator-slider" type="range" min="1" max="20" value="${f.seasons}"
              oninput="state.netflixCreatorForm.seasons=parseInt(this.value);document.getElementById('cSeasonsVal').textContent=this.value">
            <span class="creator-slider-val" id="cSeasonsVal">${f.seasons}</span>
          </div>
        </div>
        <div class="creator-field">
          <span class="creator-label">Épisodes par saison</span>
          <div class="creator-slider-row">
            <input class="creator-slider" type="range" min="1" max="100" value="${f.episodesPerSeason}"
              oninput="state.netflixCreatorForm.episodesPerSeason=parseInt(this.value);document.getElementById('cEpVal').textContent=this.value">
            <span class="creator-slider-val" id="cEpVal">${f.episodesPerSeason}</span>
          </div>
        </div>` : ''}
        <div class="creator-field">
          <span class="creator-label">Image de couverture</span>
          <div class="creator-cover-btn" data-gaze data-action="${actionPrefix}:cover">
            ${f.coverDataUrl ? '✅ Image sélectionnée' : '📁 Choisir une image'}
          </div>
          ${f.coverDataUrl ? `<div class="creator-cover-preview" style="display:block;background-image:url('${f.coverDataUrl}')"></div>` : ''}
        </div>
        ${state.keyboardTarget ? `<div style="font-size:8px;opacity:.5;text-align:center">⌨️ Clavier ouvert en bas</div>` : ''}
        <button class="creator-save-btn" style="background:linear-gradient(135deg,#a855f7,#6366f1)"
          data-gaze data-action="${actionPrefix}:save"
          ${!f.name.trim() ? 'disabled' : ''}>
          💾 Enregistrer
        </button>
      </div>`}
    </div>
  </div>`;
}

/* User content helpers */
function buildUserContentCW(){
  if(!state.userContent.length) return '';
  return state.userContent.map(uc=>{
    const emojis = ['🎬','📺','🌟','🔥','💫','🎭','🎪','🎯','🏆','💎'];
    const colors = ['#a855f7,#6366f1','#f472b6,#e91e63','#34d399,#059669','#fbbf24,#d97706','#60a5fa,#2563eb',
      '#fb923c,#ea580c','#a78bfa,#7c3aed','#f87171,#dc2626','#2dd4bf,#0d9488','#e879f9,#c026d3'];
    const emoji = emojis[uc.id % emojis.length];
    const c = colors[uc.id % colors.length];
    return `<div class="nf-cw-item" data-gaze data-action="netflix:user:play:${uc.id}">
      <div class="nf-cw-thumb" style="background:linear-gradient(135deg,${c})">${emoji}</div>
      <div class="nf-cw-info">
        <div class="nf-cw-title">${uc.name.replace(/['"]/g,'')}</div>
        <div class="nf-cw-sub">${uc.type==='series'?uc.seasons+' saisons':'Film'} • ${uc.story.slice(0,30)}${uc.story.length>30?'...':''}</div>
      </div>
      <div class="nf-cw-play">▶</div>
    </div>`;
  }).join('');
}

function buildAnimeUserContentCW(){
  if(!state.userContent.length) return '';
  return state.userContent.map(uc=>{
    const emojis = ['🎬','📺','🌟','🔥','💫','🎭','🎪','🎯','🏆','💎'];
    const colors = ['#a855f7,#6366f1','#f472b6,#e91e63','#34d399,#059669','#fbbf24,#d97706','#60a5fa,#2563eb',
      '#fb923c,#ea580c','#a78bfa,#7c3aed','#f87171,#dc2626','#2dd4bf,#0d9488','#e879f9,#c026d3'];
    const emoji = emojis[uc.id % emojis.length];
    const c = colors[uc.id % colors.length];
    return `<div class="nf-cw-item" data-gaze data-action="netflix:anime:user:play:${uc.id}">
      <div class="nf-cw-thumb" style="background:linear-gradient(135deg,${c})">${emoji}</div>
      <div class="nf-cw-info">
        <div class="nf-cw-title">${uc.name.replace(/['"]/g,'')}</div>
        <div class="nf-cw-sub">${uc.type==='series'?uc.seasons+' saisons':'Film'} • ${uc.story.slice(0,30)}${uc.story.length>30?'...':''}</div>
      </div>
      <div class="nf-cw-play">▶</div>
    </div>`;
  }).join('');
}

